With.Query:

				SELECT Capacities.ClassificationLevels,
						{{
							Fields
								-Dimension: PointsOfSale 
									--Table: PointsOfSaleCte
								-Dimension: Typologies 
									--Table: TypologiesCte
								-WithComma
                	   }}			   
					   {{
							IfRequest
								-Expression: MinimumStock
									--SUM(Capacities.MinimumStock) AS MinimumStock									
								-Expression: MaximumStock
									--SUM(Capacities.MaximumStock) AS MaximumStock									
								-Expression: MinimumVolumetry
									--SUM(Capacities.MinimumVolumetry) AS MinimumVolumetry									
								-Expression: MaximumVolumetry
									--SUM(Capacities.MaximumVolumetry) AS MaximumVolumetry									
								-Expression: IdealStock
									--SUM(Capacities.IdealStock) AS IdealStock									
								-Expression: ExpectedStock
									--SUM(Capacities.ExpectedStock) AS ExpectedStock									
								-Expression: AlertMessageId
									--MAX(Capacities.AlertMessageId) AS AlertMessageId
								-WhenRequestTotals
									--Default
										---COUNT(*) OVER () AS TotalCount
						}}						   
					FROM Fact.Capacities
					{{
                		InnerJoin 
                			-Dimension: PointsOfSale 
                				--Table: PointsOfSaleCte
								--On:PointOfSaleId-PointOfSaleId
							-Table: Capacities
					}}
	            	{{
	            		InnerJoin 
	            			-Dimension: Typologies 
	            				--Table: TypologiesCte
								--On: TypologyId-TypologyId
							-Table: Capacities
	            	}}
					{{
						Where
							-DataSource: [Fact].[Capacities]
								--Table: Capacities
					}}
					{{
                		GroupBy
                			-Dimension: PointsOfSale 
                				--Table: PointsOfSaleCte
	            			-Dimension: Typologies 
	            				--Table: TypologiesCte
	            			-Sql
	            				--Capacities.ClassificationLevels
	            	}}
					{{
                		OrderBy
                			-Dimension: PointsOfSale
	            			-Dimension: Typologies
	            			-Sql
	            				--Capacities.ClassificationLevels
	            	}}
					{{Pagination}}
